/**
 * Returns the canonical Unicode script name of [codePoint] if it belongs to one of the scripts the
 * detector tracks, or `null` otherwise. Names match the [Alphabet] enum-constant names.
 */
internal fun unicodeScriptName(codePoint: Int): String? {
    var lo = 0
    var hi = SCRIPT_RANGE_STARTS.size - 1
    var candidate = -1
    while (lo <= hi) {
        val mid = (lo + hi) ushr 1
        if (SCRIPT_RANGE_STARTS[mid] <= codePoint) {
            candidate = mid
            lo = mid + 1
        } else {
            hi = mid - 1
        }
    }
    if (candidate >= 0 && codePoint <= SCRIPT_RANGE_ENDS[candidate]) {
        return SCRIPT_NAMES[SCRIPT_RANGE_IDS[candidate]]
    }
    return null
}
